 3→$bgBase: #12121a;
 4→$bgElevated: #1a1a2e;
 5→$bgSurface: #22223a;
 6→
 7→$textPrimary: #f0f0f5;
 8→$textSecondary: #8888a0;
 9→$textMuted: #55556a;
10→
11→$accentPurple: #6c5ce7;
12→$accentPurpleLight: #8b7cf0;
13→$accentPurpleDark: #5a4bd6;
14→$accentTeal: #00cec9;
15→$accentTealLight: #33ddd9;
16→
17→$danger: #ff6b6b;
18→$success: #00b894;
19→$warning: #fdcb6e;
20→
21→// Glass
22→$glassBg: rgba(255, 255, 255, 0.03);
23→$glassBgHover: rgba(255, 255, 255, 0.06);
24→$glassBorder: rgba(255, 255, 255, 0.06);
25→$glassBorderHover: rgba(255, 255, 255, 0.12);
26→$glassBlur: 12px;
27→
28→// Spacing
29→$space1: 4px;
30→$space2: 8px;
31→$space3: 12px;
32→$space4: 16px;
33→$space5: 20px;
34→$space6: 24px;
35→$space8: 32px;
36→$space10: 40px;
37→$space12: 48px;
38→$space16: 64px;
39→$space20: 80px;
40→
41→// Radii
42→$radiusSm: 6px;
43→$radiusMd: 10px;
44→$radiusLg: 16px;
45→$radiusXl: 24px;
46→$radiusFull: 9999px;
47→
48→// Shadows
49→$shadowSm: 0 2px 8px rgba(108, 92, 231, 0.08);
50→$shadowMd: 0 4px 16px rgba(108, 92, 231, 0.12);
51→$shadowLg: 0 8px 32px rgba(108, 92, 231, 0.16);
52→$shadowGlow: 0 0 20px rgba(108, 92, 231, 0.3);
53→$shadowTealGlow: 0 0 20px rgba(0, 206, 201, 0.3);
54→
55→// Typography
56→$fontFamily: "Inter", system-ui, -apple-system, sans-serif;
57→$fontSize12: 0.75rem;
58→$fontSize13: 0.8125rem;
59→$fontSize14: 0.875rem;
60→$fontSize16: 1rem;
61→$fontSize18: 1.125rem;
62→$fontSize20: 1.25rem;
63→$fontSize24: 1.5rem;
64→$fontSize32: 2rem;
65→$fontSize40: 2.5rem;
66→$fontSize48: 3rem;
67→$fontSize64: 4rem;
68→
69→// Breakpoints
70→$bpMobile: 480px;
71→$bpTablet: 768px;
72→$bpDesktop: 1024px;
73→$bpWide: 1280px;
74→
75→// Layout
76→$navbarHeight: 64px;
77→$maxWidth: 1200px;
78→$sidebarWidth: 280px;
79→
80→// Transitions
81→$transitionFast: 150ms ease;
82→$transitionBase: 250ms ease;
83→$transitionSlow: 400ms ease;
84→

 1→@use "variables" as *;
 2→
 3→// Media queries
 4→@mixin mobile {
 5→  @media (max-width: $bpMobile) {
 6→    @content;
 7→  }
 8→}
 9→
10→@mixin tablet {
11→  @media (max-width: $bpTablet) {
12→    @content;
13→  }
14→}
15→
16→@mixin tabletUp {
17→  @media (min-width: ($bpTablet + 1)) {
18→    @content;
19→  }
20→}
21→
22→@mixin desktop {
23→  @media (min-width: $bpDesktop) {
24→    @content;
25→  }
26→}
27→
28→@mixin wide {
29→  @media (min-width: $bpWide) {
30→    @content;
31→  }
32→}
33→
34→// Glass morphism
35→@mixin glass {
36→  background: $glassBg;
37→  backdrop-filter: blur($glassBlur);
38→  -webkit-backdrop-filter: blur($glassBlur);
39→  border: 1px solid $glassBorder;
40→}
41→
42→@mixin glassHover {
43→  background: $glassBgHover;
44→  border-color: $glassBorderHover;
45→}
46→
47→// Container
48→@mixin container {
49→  width: 100%;
50→  max-width: $maxWidth;
51→  margin: 0 auto;
52→  padding: 0 $space6;
53→
54→  @include tablet {
55→    padding: 0 $space4;
56→  }
57→}
58→
59→// Truncate
60→@mixin truncate($lines: 1) {
61→  @if $lines == 1 {
62→    overflow: hidden;
63→    text-overflow: ellipsis;
64→    white-space: nowrap;
65→  } @else {
66→    display: -webkit-box;
67→    -webkit-line-clamp: $lines;
68→    -webkit-box-orient: vertical;
69→    overflow: hidden;
70→  }
71→}
72→
73→// Focus ring
74→@mixin focusRing {
75→  outline: 2px solid $accentPurple;
76→  outline-offset: 2px;
77→}
78→
79→// Scrollbar
80→@mixin customScrollbar {
81→  &::-webkit-scrollbar {
82→    width: 6px;
83→  }
84→  &::-webkit-scrollbar-track {
85→    background: transparent;
86→  }
87→  &::-webkit-scrollbar-thumb {
88→    background: $textMuted;
89→    border-radius: $radiusFull;
90→  }
91→}
92→

 1→@keyframes shimmer {
 2→  0% {
 3→    background-position: -200% 0;
 4→  }
 5→  100% {
 6→    background-position: 200% 0;
 7→  }
 8→}
 9→
10→@keyframes pulse {
11→  0%,
12→  100% {
13→    opacity: 1;
14→  }
15→  50% {
16→    opacity: 0.5;
17→  }
18→}
19→
20→@keyframes glow {
21→  0%,
22→  100% {
23→    box-shadow: 0 0 20px rgba(108, 92, 231, 0.3);
24→  }
25→  50% {
26→    box-shadow: 0 0 40px rgba(108, 92, 231, 0.5);
27→  }
28→}
29→
30→@keyframes glowBorder {
31→  0% {
32→    border-color: rgba(108, 92, 231, 0.3);
33→  }
34→  50% {
35→    border-color: rgba(108, 92, 231, 0.6);
36→  }
37→  100% {
38→    border-color: rgba(108, 92, 231, 0.3);
39→  }
40→}
41→
42→@keyframes spin {
43→  to {
44→    transform: rotate(360deg);
45→  }
46→}
47→
48→@keyframes gradientShift {
49→  0% {
50→    background-position: 0% 50%;
51→  }
52→  50% {
53→    background-position: 100% 50%;
54→  }
55→  100% {
56→    background-position: 0% 50%;
57→  }
58→}
