19→                {isActive && (
20→                  <motion.div
21→                    layoutId="navIndicator"
22→                    className={styles.indicator}
23→                    transition={{ type: "spring", stiffness: 380, damping: 30 }}
24→                  />
25→                )}
26→              </>
27→            )}
28→          </NavLink>
29→
30→          <NavLink to="/register" className={styles.link}>
31→            {({ isActive }) => (
